/**
 * Pantheon OS Live State Widget v0.2.0
 *
 * Loads real system state from pantheon-os-state.json (generated by engine/state_engine.py)
 * and renders a live status panel in the dashboard.
 *
 * Falls back gracefully if state file doesn't exist yet.
 */

(function () {
  const STATE_URL = "./data/pantheon-os-state.json";

  async function loadState() {
    try {
      const resp = await fetch(STATE_URL);
      if (!resp.ok) return null;
      return await resp.json();
    } catch (e) {
      return null;
    }
  }

  function renderLivePanel(state) {
    if (!state) return null;

    const panel = document.createElement("section");
    panel.className = "live-state-panel";
    panel.innerHTML = `
      <style>
        .live-state-panel {
          background: #111114;
          border: 1px solid #252530;
          padding: 24px;
          margin: 24px 0;
        }
        .live-state-panel h2 {
          font-size: 14px;
          text-transform: uppercase;
          letter-spacing: 1.5px;
          color: #2dd4bf;
          margin-bottom: 16px;
          padding-bottom: 8px;
          border-bottom: 1px solid #252530;
        }
        .live-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
          gap: 12px;
          margin-bottom: 20px;
        }
        .live-cell {
          background: #0a0a0c;
          border: 1px solid #252530;
          padding: 12px 16px;
        }
        .live-cell .cell-label {
          font-size: 10px;
          text-transform: uppercase;
          letter-spacing: 1.5px;
          color: #7a7a8a;
          margin-bottom: 4px;
        }
        .live-cell .cell-value {
          font-size: 14px;
          font-family: 'JetBrains Mono', monospace;
          color: #e0e0e6;
        }
        .live-cell .cell-value.good { color: #10b981; }
        .live-cell .cell-value.warn { color: #f59e0b; }
        .live-cell .cell-value.blocked { color: #ef4444; }
        .live-agents {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }
        .live-agent {
          display: flex;
          align-items: center;
          gap: 12px;
          background: #0a0a0c;
          border: 1px solid #252530;
          padding: 10px 16px;
        }
        .live-agent .agent-dot {
          width: 8px;
          height: 8px;
          flex-shrink: 0;
        }
        .live-agent .agent-dot.active { background: #10b981; }
        .live-agent .agent-dot.unknown { background: #7a7a8a; }
        .live-agent .agent-name {
          font-weight: 600;
          font-size: 13px;
          min-width: 160px;
        }
        .live-agent .agent-role {
          font-size: 12px;
          color: #7a7a8a;
          flex: 1;
        }
        .live-agent .agent-realm {
          font-size: 11px;
          color: #0d9488;
        }
        .live-ventures {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
          gap: 8px;
        }
        .live-venture {
          background: #0a0a0c;
          border: 1px solid #252530;
          padding: 10px 16px;
          display: flex;
          justify-content: space-between;
          align-items: center;
        }
        .live-venture .venture-name {
          font-size: 13px;
          font-weight: 500;
        }
        .live-venture .venture-meta {
          font-size: 11px;
          color: #7a7a8a;
        }
        .live-venture .venture-status {
          font-size: 10px;
          text-transform: uppercase;
          letter-spacing: 1px;
          padding: 2px 8px;
          border-radius: 2px;
        }
        .live-venture .venture-status.active { background: rgba(16,185,129,0.15); color: #10b981; }
        .live-venture .venture-status.pre-launch { background: rgba(245,158,11,0.15); color: #f59e0b; }
        .live-venture .venture-status.experiment { background: rgba(74,158,255,0.15); color: #4a9eff; }
        .live-venture.prototype .venture-status { background: rgba(139,92,246,0.15); color: #8b5cf6; }
        .live-commits {
          margin-top: 16px;
        }
        .live-commit {
          display: flex;
          gap: 12px;
          padding: 6px 0;
          font-size: 12px;
          font-family: 'JetBrains Mono', monospace;
          border-bottom: 1px solid #18181c;
        }
        .live-commit .commit-hash {
          color: #0d9488;
          min-width: 60px;
        }
        .live-commit .commit-msg {
          color: #7a7a8a;
          flex: 1;
        }
        .live-commit .commit-date {
          color: #7a7a8a;
          min-width: 100px;
          text-align: right;
        }
        .live-footer {
          margin-top: 12px;
          font-size: 11px;
          color: #7a7a8a;
        }
      </style>
      <h2>◆ Live System State</h2>
      <div class="live-grid">
        <div class="live-cell">
          <div class="cell-label">Branch</div>
          <div class="cell-value">${state.git.branch}</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Last Commit</div>
          <div class="cell-value">${state.git.last_commit.hash} — ${state.git.last_commit.message.substring(0, 40)}…</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Working Tree</div>
          <div class="cell-value ${state.git.working_tree_clean ? 'good' : 'warn'}">${state.git.working_tree_clean ? 'Clean' : 'Uncommitted changes'}</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Remote</div>
          <div class="cell-value ${state.git.remote_synced ? 'good' : 'blocked'}">${state.git.remote_synced ? 'Synced' : 'Out of sync'}</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Agents</div>
          <div class="cell-value">${state.summary.active_agent_count} active</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Realms</div>
          <div class="cell-value">${state.summary.realm_count} established</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Ventures</div>
          <div class="cell-value">${state.summary.active_venture_count} active / ${state.summary.venture_count} total</div>
        </div>
        <div class="live-cell">
          <div class="cell-label">Budget Period</div>
          <div class="cell-value">${state.summary.budget?.period || '—'}</div>
        </div>
      </div>

      ${state.runtime_topology ? `
        <h2>◆ Runtime Topology</h2>
        <div class="live-grid">
          <div class="live-cell">
            <div class="cell-label">Hosts</div>
            <div class="cell-value">${state.runtime_topology.summary.host_count}</div>
          </div>
          <div class="live-cell">
            <div class="cell-label">Host Overseers</div>
            <div class="cell-value">${state.runtime_topology.summary.overseer_count}</div>
          </div>
          <div class="live-cell">
            <div class="cell-label">Hermes Instances</div>
            <div class="cell-value">${state.runtime_topology.summary.hermes_instance_count}</div>
          </div>
          <div class="live-cell">
            <div class="cell-label">Agent Slots</div>
            <div class="cell-value">${state.runtime_topology.summary.active_slot_count} active / ${state.runtime_topology.summary.agent_slot_count} total</div>
          </div>
        </div>
        <div class="live-agents">
          ${state.runtime_topology.hosts.map(host => `
            <div class="live-agent">
              <div class="agent-dot ${(host.overseer && host.overseer.status === 'active') ? 'active' : 'unknown'}"></div>
              <div class="agent-name">${host.label}</div>
              <div class="agent-role">${host.overseer ? `${host.overseer.name} · host overseer` : 'No overseer registered'}</div>
              <div class="agent-realm">${host.runtimes.map(runtime => `${runtime.name}: ${runtime.slot_summary.active}/${runtime.slot_summary.total} slots`).join(' · ')}</div>
            </div>
          `).join('')}
        </div>
      ` : ''}

      <h2>◆ Agents</h2>
      <div class="live-agents">
        ${state.agents.map(a => `
          <div class="live-agent">
            <div class="agent-dot ${a.status === 'active' ? 'active' : 'unknown'}"></div>
            <div class="agent-name">${a.name}</div>
            <div class="agent-role">${a.role}</div>
            ${a.realm ? `<div class="agent-realm">realm: ${a.realm}</div>` : ''}
          </div>
        `).join('')}
      </div>

      <h2>◆ Ventures</h2>
      <div class="live-ventures">
        ${(state.ventures || []).map(v => `
          <div class="live-venture ${v.stage || ''}">
            <div>
              <div class="venture-name">${v.name}</div>
              <div class="venture-meta">${v.stage} · ${v.health || '—'}</div>
            </div>
            <div class="venture-status ${v.status || ''}">${v.status || 'unknown'}</div>
          </div>
        `).join('')}
      </div>

      <div class="live-commits">
        <h2>◆ Recent Activity</h2>
        ${state.git.recent_commits.slice(0, 5).map(c => `
          <div class="live-commit">
            <span class="commit-hash">${c.hash}</span>
            <span class="commit-msg">${c.message}</span>
            <span class="commit-date">${c.date.split(' ').slice(0, 2).join(' ')}</span>
          </div>
        `).join('')}
      </div>

      <div class="live-footer">
        Generated ${state.meta.generated_at} · Engine ${state.meta.engine_version} · Source: ${state.meta.source}
      </div>
    `;

    return panel;
  }

  // Auto-mount into dashboard
  document.addEventListener("DOMContentLoaded", async () => {
    const state = await loadState();
    if (!state) return; // No state file — dashboard works with mock data

    const panel = renderLivePanel(state);
    if (!panel) return;

    // Insert after the hero section if it exists, otherwise at top of main
    const main = document.querySelector("main");
    const hero = document.querySelector(".hero");
    if (hero && hero.nextSibling) {
      main.insertBefore(panel, hero.nextSibling);
    } else if (main) {
      main.prepend(panel);
    }
  });
})();
